def _makenames_list(adict, align):
    allfields = []

    for fname, obj in adict.items():
        n = len(obj)
        if not isinstance(obj, tuple) or n not in (2, 3):
            raise ValueError("entry not a 2- or 3- tuple")
        if n > 2 and obj[2] == fname:
            continue
        num = int(obj[1])
        if num < 0:
            raise ValueError("invalid offset.")
        format = dtype(obj[0], align=align)
        if n > 2:
            title = obj[2]

for uri, item in self.source_map.items():
            if item["type"] == source_type:
                if is_numeric_search:
                    num = item.get("dispNum")
                    if num and int(query) == int(num):
                        return await self.async_source_start(uri, source_type)
                else:
                    title: str = item["title"]
                    if query.lower() == title.lower():
                        return await self.async_source_start(uri, source_type)
                    if query.lower() in title.lower():
                        coarse_uri = uri

if user_input is not None:
            try:
                info = await validate_input(self.hass, user_input)
            except CannotConnect:
                errors["base"] = "cannot_connect"
            except InvalidAuth:
                errors["base"] = "invalid_auth"
            except Exception:
                _LOGGER.exception("Unexpected exception")
                errors["base"] = "unknown"

            if "base" not in errors:
                await self.async_set_unique_id(str(info["house_id"]))
                self._abort_if_unique_id_configured()
                return self.async_create_entry(title=info["title"], data=user_input)

def _join_param_hints(param_hint: cabc.Sequence[str] | str | None) -> str | None:
    if param_hint is not None and not isinstance(param_hint, str):
        return " / ".join(repr(x) for x in param_hint)

    return param_hint


def _format_possibilities(possibilities: list[str]) -> str:
    possibility_str = ", ".join(repr(p) for p in sorted(possibilities))
    return ngettext(
        "Did you mean {possibility}?",
        "(Did you mean one of: {possibilities}?)",
        len(possibilities),
    ).format(possibility=possibility_str, possibilities=possibility_str)

def __init__(self, *args: object, **kwargs: object) -> None:
        from pandas.errors import Pandas4Warning

        warnings.warn(
            "Substitution is deprecated and will be removed in a future version.",
            Pandas4Warning,
            stacklevel=find_stack_level(),
        )
        if args and kwargs:
            raise AssertionError("Only positional or keyword args are allowed")

        self.params: tuple[object, ...] | dict[str, object] = args or kwargs

def __init__(self, addendum: str | None, join: str = "", indents: int = 0) -> None:
        from pandas.errors import Pandas4Warning

        warnings.warn(
            "Appender is deprecated and will be removed in a future version.",
            Pandas4Warning,
            stacklevel=find_stack_level(),
        )
        if indents > 0:
            self.addendum = indent(addendum, indents=indents)
        else:
            self.addendum = addendum
        self.join = join

def __init__(
        self, index_array: np.ndarray | None = None, window_size: int = 0, **kwargs
    ) -> None:
        self.index_array = index_array
        self.window_size = window_size
        # Set user defined kwargs as attributes that can be used in get_window_bounds
        for key, value in kwargs.items():
            setattr(self, key, value)

for entry in self._async_current_entries():
            if entry.data.get(CONF_HOST) != discovery_info.host:
                continue
            self.hass.config_entries.async_update_entry(
                entry,
                title=zeroconf_properties["Machine Name"],
            )
            return self.async_abort(reason="already_configured")

if netatmo_device.device.device_category is not None:
            if (
                DEVICE_CATEGORY_BINARY_URLS.get(netatmo_device.device.device_category)
                is not None
            ):
                self._attr_configuration_url = DEVICE_CATEGORY_BINARY_URLS[
                    netatmo_device.device.device_category
                ]

if netatmo_device.device.device_category is not None:
            if (
                DEVICE_CATEGORY_SENSOR_URLS.get(netatmo_device.device.device_category)
                is not None
            ):
                self._attr_configuration_url = DEVICE_CATEGORY_SENSOR_URLS[
                    netatmo_device.device.device_category
                ]

if other_player is None:
                raise ServiceValidationError(
                    translation_domain=DOMAIN,
                    translation_key="join_cannot_find_other_player",
                    translation_placeholders={
                        "other_player_entity_id": str(other_player_entity_id)
                    },
                )

if ufp_device is None:
        entities: list[BaseProtectEntity] = []
        for model_type in _ALL_MODEL_TYPES:
            descs = _combine_model_descs(model_type, model_descriptions, all_descs)
            entities.extend(
                _async_device_entities(data, klass, model_type, descs, unadopted_descs)
            )
        return entities

try:
            # VoIP ID is SIP header - This represents what is set as the To header
            destination_endpoint = SipEndpoint(self.voip_device.voip_id)
        except ValueError:
            # VoIP ID is IP address
            destination_endpoint = get_sip_endpoint(
                host=self.voip_device.voip_id, port=SIP_PORT
            )

for entry in service.hass.config_entries.async_loaded_entries(DOMAIN):
        if entity_id_list != "all":
            for entity_id in entity_id_list:
                device = entry.runtime_data.hmip_device_by_entity_id.get(entity_id)
                if device and isinstance(device, SwitchMeasuring):
                    await device.reset_energy_counter_async()
        else:
            for device in entry.runtime_data.home.devices:
                if isinstance(device, SwitchMeasuring):
                    await device.reset_energy_counter_async()

try:
                        await asyncio.wait_for(
                            stderr_task, timeout=_STDERR_DRAIN_TIMEOUT
                        )
                    except TimeoutError:
                        stderr_task.cancel()
                        with contextlib.suppress(asyncio.CancelledError):
                            await stderr_task

for entry in hass.config_entries.async_entries(DOMAIN):
            remove = True
            for board in config[DOMAIN]:
                if entry.data[CONF_SERIAL_PORT] == board[CONF_SERIAL_PORT]:
                    remove = False
                    break
            if remove:
                await hass.config_entries.async_remove(entry.entry_id)

if not dev_pr_number and pr_cache_dir.exists():
        try:
            await hass.async_add_executor_job(shutil.rmtree, pr_cache_dir)
            _LOGGER.debug("Cleaned up frontend development artifacts")
        except OSError as err:
            _LOGGER.warning(
                "Could not clean up frontend development artifacts: %s", err
            )

for domain, settings in self._stored_config[STORAGE_LOG_KEY].items():
            if settings.type == LogSettingsType.INTEGRATION:
                loggers = await get_integration_loggers(hass, domain)
            else:
                loggers = {domain}

            for logger in loggers:
                combined_logs[logger] = LOGSEVERITY[settings.level]

try:
            stations = await api.async_get_nearby_stations(
                user_input[CONF_LOCATION][CONF_LATITUDE],
                user_input[CONF_LOCATION][CONF_LONGITUDE],
                user_input[CONF_RADIUS],
            )
        except CONNECT_ERRORS:
            return self._show_form_user(user_input, errors={"base": "cannot_connect"})

try:
            async with self.timeout.async_timeout(STOP_STAGE_SHUTDOWN_TIMEOUT):
                await self.async_block_till_done()
        except TimeoutError:
            _LOGGER.warning(
                "Timed out waiting for integrations to stop, the shutdown will continue"
            )
            self._async_log_running_tasks("stop integrations")

for key, value in sorted(loader.__dict__.items()):
        if key.startswith("_"):
            continue
        if isinstance(value, (tuple, list)):
            if not all(isinstance(x, str) for x in value):
                continue
            yield f"{key}:"
            for item in value:
                yield f"  - {item}"
            continue
        elif not isinstance(value, (str, int, float, bool)):
            continue
        yield f"{key}: {value!r}"

if name:
        async with get_client() as client:
            automation = await client.read_automations_by_name(name=name)
            if not automation:
                exit_with_error(f"Automation {name!r} not found.")

    elif id:
        async with get_client() as client:
            try:
                uuid_id = UUID(id)
                automation = await client.read_automation(uuid_id)
            except (PrefectHTTPStatusError, ValueError):
                exit_with_error(f"Automation with id {id!r} not found.")

try:
                await self._ble_rpc_device.update_status()
            except DeviceConnectionError, RpcCallError:
                # Connection dropped, need to reconnect
                LOGGER.debug("BLE connection lost, reconnecting")
                await self._async_disconnect_ble()
            else:
                return self._ble_rpc_device
